VALUES
  ('elementary-f29af906-moex-00498', 'elementary-f29af906', 'elementary-f29af906-moex-112-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '關於土地登記規則中，對土地權利變更登記、信託登記、限制登記、更名登記之規定，下列敘述何 者錯誤？', '["土地總登記後，土地所有權移轉、分割、合併、增減或消滅時，應為變更登記", "土地權利信託登記，係指土地權利依信託法辦理信託而為變更之登記", "限制登記，包括預告登記、查封、假扣押、假執行、假處分或破產登記，及其他依法律所為禁止 處分之登記", "土地權利登記後，權利人之姓名或名稱有變更者，應申請更名登記"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "9241e7954067", "answer_pdf_sha1": "f9472601e84e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00499', 'elementary-f29af906', 'elementary-f29af906-moex-112-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地登記規則之規定，土地所有權狀或他項權利證明書損壞或滅失，應由何人申請換給或補給？', '["登記義務人", "登記名義人", "其他權利人", "建物所有權人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "9241e7954067", "answer_pdf_sha1": "f9472601e84e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00500', 'elementary-f29af906', 'elementary-f29af906-moex-112-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地登記規則之規定，信託專簿，應自塗銷信託登記或信託歸屬登記之日起保存多久時間？', '["1個月", "6個月", "3年", "15年"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "9241e7954067", "answer_pdf_sha1": "f9472601e84e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00501', 'elementary-f29af906', 'elementary-f29af906-moex-112-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地登記規則之規定，申請繼承登記應提出一定之文件；那種情形下，得不提出繼承系統表？', '["因法院確定判決申請繼承登記者", "能以電腦處理達成查詢者", "無繼承人者", "設有遺產管理人者"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "9241e7954067", "answer_pdf_sha1": "f9472601e84e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00502', 'elementary-f29af906', 'elementary-f29af906-moex-112-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依都市計畫法規定，內政部或直轄市政府得依據地方實際情況，對於一定之事項，於本法施行細則 中作必要之規定。所稱之一定事項，並不包含下列那一個選項？', '["基地面積或基地內應保留空地之比率", "違反土地使用管制之處罰", "基地內前後側院之深度及寬度", "交通、景觀或防火等事項"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "9241e7954067", "answer_pdf_sha1": "f9472601e84e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00503', 'elementary-f29af906', 'elementary-f29af906-moex-112-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '甲於臺北之陽明山國家公園範圍內有一土地，於 111 年欲申請興建農舍。其使用應合於下列那一項 之土地使用管制規定？', '["臺北市之都市計畫土地使用管制規定", "陽明山國家公園計畫之土地使用管制規定", "臺北市之國土計畫土地使用管制規定", "新北市區域計畫之非都市土地使用管制"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "9241e7954067", "answer_pdf_sha1": "f9472601e84e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00504', 'elementary-f29af906', 'elementary-f29af906-moex-112-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依區域計畫法施行細則之規定，供山坡地範圍外之農業區內建築使用者，為何種使用地？', '["甲種建築用地", "乙種建築用地", "丙種建築用地", "丁種建築用地"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "9241e7954067", "answer_pdf_sha1": "f9472601e84e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00505', 'elementary-f29af906', 'elementary-f29af906-moex-112-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依非都市土地使用管制規則第6條第3項規定，有關土地使用需要申請區位許可者，是那一種使用地？', '["丁種建築用地", "國土保安用地", "殯葬用地", "海域用地"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "9241e7954067", "answer_pdf_sha1": "f9472601e84e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00506', 'elementary-f29af906', 'elementary-f29af906-moex-112-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '關於民法規定之區分地上權，下列敘述何者錯誤？', '["稱區分地上權者，謂以在他人土地上下之一定空間範圍內設定之地上權", "區分地上權依規定以時價補償或延長期間，足以影響第三人之權利時，應對該第三人為相當之補償", "同一土地有區分地上權與以使用收益為目的之物權同時存在者，其後設定物權之權利行使，不得 妨害先設定之物權", "區分地上權人得與其設定之土地上下有使用、收益權利之人，約定相互間使用收益之限制。其約 定未經土地所有人同意者，不生效力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "9241e7954067", "answer_pdf_sha1": "f9472601e84e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00507', 'elementary-f29af906', 'elementary-f29af906-moex-112-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '為促進土地利用，擴大辦理農地重劃，中央主管機關得訂定辦法，獎勵土地所有權人自行辦理之。 其辦理需要經重劃區內私有土地所有權人多少比例以上，而其所有面積亦達私有土地面積多少比例 以上者之同意？', '["所有土地所有權人三分之二以上，而其所有面積亦達重劃區全部土地面積三分之二以上", "私有土地所有權人三分之二以上，而其所有面積亦達私有土地面積三分之二以上", "私有土地所有權人二分之一以上，而其所有面積亦達私有土地面積二分之一以上", "私有土地所有權人三分之二以上，而其所有面積亦達私有土地面積四分之三以上"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "9241e7954067", "answer_pdf_sha1": "f9472601e84e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0402", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL)
